import{_ as a,o as t,c as o,a5 as l}from"./chunks/framework.B5tqjWbr.js";const h=JSON.parse('{"title":"概念：Boost 控制中断服务程序（control interrupt service routine / control ISR）软件骨架","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：Boost 控制中断服务程序（control interrupt service routine / control ISR）软件骨架","tags":["power-electronics"],"status":"learning","summary":"控制中断服务程序（control interrupt service routine / control ISR）是电源控制软件里按固定周期运行的核心函数。它通常完成："},"headers":[],"relativePath":"content/power/concepts/boost-firmware-skeleton.md","filePath":"content/power/concepts/boost-firmware-skeleton.md","lastUpdated":null}'),s={name:"content/power/concepts/boost-firmware-skeleton.md"};function n(i,e,r,p,c,d){return t(),o("div",null,[...e[0]||(e[0]=[l(`<h1 id="概念-boost-控制中断服务程序-control-interrupt-service-routine-control-isr-软件骨架" tabindex="-1">概念：Boost 控制中断服务程序（control interrupt service routine / control ISR）软件骨架 <a class="header-anchor" href="#概念-boost-控制中断服务程序-control-interrupt-service-routine-control-isr-软件骨架" aria-label="Permalink to &quot;概念：Boost 控制中断服务程序（control interrupt service routine / control ISR）软件骨架&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>控制中断服务程序（control interrupt service routine / control ISR）是电源控制软件里按固定周期运行的核心函数。它通常完成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>读取采样 -&gt; 保护判断 -&gt; 控制计算 -&gt; 限幅 -&gt; 更新调制输出 -&gt; 记录状态</span></span></code></pre></div><p>本节用 Boost 电压闭环做一个通用学习骨架，不涉及任何公司内部代码、产品参数或客户项目数据。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）软件不是只有控制算法。一个能运行的基本软件至少要把这些事情串起来：</p><ul><li>模数转换器（analog-to-digital converter / ADC）采样。</li><li>脉宽调制（pulse-width modulation / PWM）占空比更新。</li><li>离散比例积分控制器（discrete proportional-integral controller / discrete PI）计算。</li><li>过压、欠压、过流等保护。</li><li>故障锁存和安全关断。</li></ul><p>如果只会 PI 公式，但看不懂 ISR 里的数据流，就很难阅读完整 C 工程。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>控制 ISR 像一条固定节拍的流水线。每来一次中断，软件只允许做一小段确定的事情：</p><ol><li>看一眼当前电压和电流。</li><li>判断是否危险。</li><li>如果安全，就计算下一次占空比。</li><li>如果危险，就关断调制输出，并锁存故障。</li></ol><p>故障锁存的意思是：一旦出现严重故障，不因为下一次采样恢复正常就自动重新开机。真实 UPS 需要明确的复位条件和状态机。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>控制 ISR 的核心可以写成伪代码。下面的 <code>OV</code>、<code>UV</code>、<code>OC</code> 分别表示过压阈值（over-voltage threshold / OV）、欠压阈值（under-voltage threshold / UV）和过流阈值（over-current threshold / OC）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if fault_latched:</span></span>
<span class="line"><span>    duty = 0</span></span>
<span class="line"><span>elif Vout &gt; OV:</span></span>
<span class="line"><span>    fault = over_voltage</span></span>
<span class="line"><span>    duty = 0</span></span>
<span class="line"><span>elif Vout &lt; UV:</span></span>
<span class="line"><span>    fault = under_voltage</span></span>
<span class="line"><span>    duty = 0</span></span>
<span class="line"><span>elif abs(IL) &gt; OC:</span></span>
<span class="line"><span>    fault = over_current</span></span>
<span class="line"><span>    duty = 0</span></span>
<span class="line"><span>else:</span></span>
<span class="line"><span>    error = Vref - Vout</span></span>
<span class="line"><span>    integrator = clamp(integrator + Ki * error * Ts)</span></span>
<span class="line"><span>    duty = clamp(Kp * error + integrator, Dmin, Dmax)</span></span></code></pre></div><p>这段伪代码的重点不是语法，而是顺序：故障锁存优先，其次保护判断，最后才允许控制器更新占空比。</p><h2 id="_5-仿真观察" tabindex="-1">5. 仿真观察 <a class="header-anchor" href="#_5-仿真观察" aria-label="Permalink to &quot;5. 仿真观察&quot;">​</a></h2><p>使用脚本：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>simulations/python/boost_firmware_skeleton.py</span></span></code></pre></div><p>图中观察四件事：</p><ul><li>输出电压是否跟踪参考值。</li><li>估算电感电流是否低于过流阈值。</li><li>占空比命令是否在运行中变化。</li><li>故障码是否保持为 <code>NONE</code>，或者在故障后锁存。</li></ul><p>可以故意降低过压阈值来观察故障锁存：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>python simulations/python/boost_firmware_skeleton.py --over-voltage 90 --output simulations/results/boost_firmware_ov_fault.png</span></span></code></pre></div><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>真实 C 工程中，这个骨架可能分散在多个文件：</p><ul><li><code>adc.c</code> 或驱动层：采样触发、转换结果读取。</li><li><code>pwm.c</code> 或驱动层：比较寄存器、占空比更新、关断输出。</li><li><code>control.c</code>：控制 ISR、PI 控制器、前馈、限幅。</li><li><code>protection.c</code>：过压、欠压、过流、采样异常。</li><li><code>state_machine.c</code>：启动、运行、故障、恢复。</li></ul><p>阅读时不要只找一个 <code>PI()</code> 函数。要沿着“ADC 数据从哪里来、保护在哪里判断、PWM 在哪里更新、故障如何锁存”这条链路追踪。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>错误理解：控制算法就是固件主体。<br> 正确理解：控制算法只是固件的一部分，保护、状态机、驱动接口和参数管理同样关键。</p></li><li><p>错误理解：故障采样恢复正常后就可以自动继续输出。<br> 正确理解：严重故障通常要锁存，等待状态机确认复位条件。</p></li><li><p>错误理解：保护逻辑都可以放在慢任务里。<br> 正确理解：过流、过压等快速风险通常要在 ISR 或硬件比较器里快速处理。</p></li><li><p>错误理解：Python 骨架和真实 C 工程差不多。<br> 正确理解：Python 骨架只帮助理解数据流。真实工程还要处理外设寄存器、定点数、实时性、异常路径和硬件保护。</p></li></ul><h2 id="_8-保密边界" tabindex="-1">8. 保密边界 <a class="header-anchor" href="#_8-保密边界" aria-label="Permalink to &quot;8. 保密边界&quot;">​</a></h2><p>本仓库只记录公开的、教学用的简化模型和个人理解，不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据、内部通信协议细节或任何无法公开复述的调试结论。向导师请教时，可以展示本节生成的 Python 波形、参数、伪代码和自己的问题，但不要把公司工程文件复制进本仓库。</p><h2 id="_9-验收标准" tabindex="-1">9. 验收标准 <a class="header-anchor" href="#_9-验收标准" aria-label="Permalink to &quot;9. 验收标准&quot;">​</a></h2><ul><li>能画出采样、保护、控制、限幅、脉宽调制（pulse-width modulation / PWM）更新的控制中断服务程序（control interrupt service routine / control ISR）数据流。</li><li>能解释为什么故障锁存后占空比命令保持为 0，而不是采样恢复正常后自动重启。</li><li>能在 <code>simulations/results/boost_firmware_skeleton.png</code> 上指出输出电压、估算电感电流、占空比命令和故障码。</li><li>能说明哪些逻辑适合放在 ISR，哪些逻辑更适合放在状态机。</li><li>能基于脚本中的 <code>control_isr()</code> 准备 C 工程代码阅读问题。</li></ul><h2 id="_10-复盘问题" tabindex="-1">10. 复盘问题 <a class="header-anchor" href="#_10-复盘问题" aria-label="Permalink to &quot;10. 复盘问题&quot;">​</a></h2><ul><li>打开 <code>simulations/results/boost_firmware_skeleton.png</code>，最终故障码是什么？最终占空比是多少？</li><li>运行 <code>python simulations/python/boost_firmware_skeleton.py --over-voltage 90 --output simulations/results/boost_firmware_ov_fault.png</code> 后，故障发生后占空比是否恢复？为什么？</li><li>如果真实 C 工程里保护判断放在比例积分控制器之后，可能有什么风险？</li></ul><h2 id="_11-导师问题" tabindex="-1">11. 导师问题 <a class="header-anchor" href="#_11-导师问题" aria-label="Permalink to &quot;11. 导师问题&quot;">​</a></h2><ul><li>我用 <code>boost_firmware_skeleton.py</code> 看到正常运行时最终故障码是 <code>NONE</code>，占空比约 0.526。公司代码中 Boost 或功率因数校正（power factor correction / PFC）控制 ISR 的数据流是否也是“采样、保护、控制、限幅、更新 PWM”？</li><li>我把 <code>--over-voltage 90</code> 后会触发过压故障并关断占空比。公司工程里故障锁存和故障清除通常由哪个模块负责？</li><li>如果某些过流保护由硬件比较器处理，固件 ISR 里还会不会重复检查软件过流阈值？</li></ul>`,38)])])}const _=a(s,[["render",n]]);export{h as __pageData,_ as default};
